sys_variable_value.value:
(function(outputs, steps, params, stepResult, assertEqual) {
  var emailGr = new GlideRecord('sys_email');
  emailGr.addQuery('subject', '[ATF Test Data] Email Parsing Utilities Test Email');
  emailGr.orderByDesc('sys_created_on');
  emailGr.setLimit(1);
  emailGr.query();
  if (!emailGr.next()) {
    stepResult.setFailed('FAIL: Could not find test sys_email record created in Step 1');
    return;
  }
  var emailSysId = emailGr.getValue('sys_id');
  var emailRef = new GlideRecord('sys_email');
  emailRef.get(emailSysId);
  var inputs = { email: emailRef };
  var result = sn_fd.FlowAPI.getRunner().action('global.parse_email_body_text').inForeground().withInputs(inputs).run();
  var actionOutputs = result.getOutputs();
  var emailVar = actionOutputs['email_variables'] || actionOutputs['email_var'];
  if (!emailVar) { stepResult.setFailed('FAIL: email_variables/email_var output was null. Keys: ' + Object.keys(actionOutputs).join(',')); return; }
  var parsed = (typeof emailVar === 'string') ? JSON.parse(emailVar) : emailVar;
  if (parsed['Priority'] !== 'High') { stepResult.setFailed('FAIL: Priority expected "High", got: ' + parsed['Priority']); return; }
  if (parsed['Category'] !== 'Software') { stepResult.setFailed('FAIL: Category expected "Software", got: ' + parsed['Category']); return; }
  if (parsed['Assignment Group'] !== 'Service Desk') { stepResult.setFailed('FAIL: Assignment Group expected "Service Desk", got: ' + parsed['Assignment Group']); return; }
  if (Object.keys(parsed).length !== 8) { stepResult.setFailed('FAIL: Expected 8 pairs, got ' + Object.keys(parsed).length + ': ' + JSON.stringify(parsed)); return; }
  stepResult.setSuccess();
  stepResult.setOutputMessage('PASS: All 8 key-value pairs extracted correctly. Result: ' + JSON.stringify(parsed));
})(outputs, steps, params, stepResult, assertEqual);
